--
-- Name: fn_recalc_folha_totais(integer); Type: FUNCTION; Schema: public; Owner: praxis_demo_owner
--

CREATE FUNCTION public.fn_recalc_folha_totais(folha_id integer) RETURNS void
    LANGUAGE plpgsql
    AS $$
declare
  v_add numeric;
  v_disc numeric;
begin
  select coalesce(sum(valor), 0) into v_add from eventos_folha where folha_pagamento_id = folha_id and tipo = 'ADICIONAL';
  select coalesce(sum(valor), 0) into v_disc from eventos_folha where folha_pagamento_id = folha_id and tipo = 'DESCONTO';

  update folhas_pagamento fp
     set total_descontos = v_disc,
         salario_liquido = fp.salario_bruto + coalesce(v_add, 0) - coalesce(v_disc, 0)
   where fp.id = folha_id;
end;
$$;


ALTER FUNCTION public.fn_recalc_folha_totais(folha_id integer) OWNER TO praxis_demo_owner;

--
-- Name: fn_trg_eventos_folha_recalc(); Type: FUNCTION; Schema: public; Owner: praxis_demo_owner
--

CREATE FUNCTION public.fn_trg_eventos_folha_recalc() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
declare
  v_fid integer;
begin
  v_fid := coalesce(NEW.folha_pagamento_id, OLD.folha_pagamento_id);
  perform fn_recalc_folha_totais(v_fid);
  if (TG_OP = 'DELETE') then
    return OLD;
  else
    return NEW;
  end if;
end;
$$;


ALTER FUNCTION public.fn_trg_eventos_folha_recalc() OWNER TO praxis_demo_owner;

--
-- Name: fn_trg_funcionarios_hist(); Type: FUNCTION; Schema: public; Owner: praxis_demo_owner
--

CREATE FUNCTION public.fn_trg_funcionarios_hist() RETURNS trigger
    LANGUAGE plpgsql
    AS $$
BEGIN
  -- Histórico salarial
  IF NEW.salario IS DISTINCT FROM OLD.salario THEN
    UPDATE historicos_salariais
      SET data_fim = COALESCE(data_fim, CURRENT_DATE)
      WHERE funcionario_id = OLD.id AND data_fim IS NULL;
      VALUES (NEW.id, NEW.salario, CURRENT_DATE, 'Ajuste salarial');
  END IF;

  -- Histórico de cargos
  IF NEW.cargo_id IS DISTINCT FROM OLD.cargo_id THEN
    UPDATE historicos_cargos
      SET data_fim = COALESCE(data_fim, CURRENT_DATE)
      WHERE funcionario_id = OLD.id AND data_fim IS NULL;
      VALUES (NEW.id, NEW.cargo_id, CURRENT_DATE, 'Mudança de cargo');
  END IF;

  RETURN NEW;
END;
$$;


ALTER FUNCTION public.fn_trg_funcionarios_hist() OWNER TO praxis_demo_owner;

