--
-- Name: vw_analytics_folha_pagamento; Type: VIEW; Schema: public; Owner: praxis_demo_owner
--

CREATE VIEW public.vw_analytics_folha_pagamento AS
 WITH active_team AS (
         SELECT em.funcionario_id,
            em.equipe_id,
            em.papel,
            row_number() OVER (PARTITION BY em.funcionario_id ORDER BY COALESCE(em.data_entrada, '1900-01-01'::date) DESC, em.id DESC) AS rn
           FROM public.equipe_membros em
          WHERE (em.data_saida IS NULL)
        ), event_totals AS (
         SELECT ef.folha_pagamento_id,
            count(*) AS qtd_eventos,
            count(*) FILTER (WHERE (ef.tipo = 'PROVENTO'::text)) AS qtd_proventos,
            count(*) FILTER (WHERE (ef.tipo = 'DESCONTO'::text)) AS qtd_descontos,
            count(*) FILTER (WHERE (ef.tipo = 'ADICIONAL'::text)) AS qtd_adicionais,
            (COALESCE(sum(ef.valor) FILTER (WHERE (ef.tipo = 'PROVENTO'::text)), (0)::numeric))::numeric(18,2) AS valor_proventos,
            (COALESCE(sum(ef.valor) FILTER (WHERE (ef.tipo = 'DESCONTO'::text)), (0)::numeric))::numeric(18,2) AS valor_descontos_eventos,
            (COALESCE(sum(ef.valor) FILTER (WHERE (ef.tipo = 'ADICIONAL'::text)), (0)::numeric))::numeric(18,2) AS valor_adicionais,
            count(DISTINCT ef.descricao) AS qtd_tipos_evento,
            string_agg(DISTINCT ef.descricao, ', '::text ORDER BY ef.descricao) AS eventos_descricao
           FROM public.eventos_folha ef
          GROUP BY ef.folha_pagamento_id
        ), base AS (
         SELECT fp.id AS folha_pagamento_id,
            fp.funcionario_id,
            f.nome_completo,
            i.codinome,
            i.universo,
            i.exposicao_publica,
            c.id AS cargo_id,
            c.nome AS cargo,
            d.id AS departamento_id,
            d.nome AS departamento,
            at.equipe_id,
            e.nome AS equipe,
            at.papel AS papel_equipe,
            b_1.id AS base_id,
            b_1.nome AS base,
            b_1.tipo AS tipo_base,
            b_1.sigilo AS sigilo_base,
            fp.ano,
            fp.mes,
            make_date(fp.ano, fp.mes, 1) AS competencia,
            fp.data_pagamento,
            (fp.salario_bruto)::numeric(18,2) AS salario_bruto,
            (fp.total_descontos)::numeric(18,2) AS total_descontos,
            (fp.salario_liquido)::numeric(18,2) AS salario_liquido,
            COALESCE(et.qtd_eventos, (0)::bigint) AS qtd_eventos,
            COALESCE(et.qtd_proventos, (0)::bigint) AS qtd_proventos,
            COALESCE(et.qtd_descontos, (0)::bigint) AS qtd_descontos,
            COALESCE(et.qtd_adicionais, (0)::bigint) AS qtd_adicionais,
            COALESCE(et.qtd_tipos_evento, (0)::bigint) AS qtd_tipos_evento,
            (COALESCE(et.valor_proventos, (0)::numeric))::numeric(18,2) AS valor_proventos,
            (COALESCE(et.valor_descontos_eventos, (0)::numeric))::numeric(18,2) AS valor_descontos_eventos,
            (COALESCE(et.valor_adicionais, (0)::numeric))::numeric(18,2) AS valor_adicionais,
            et.eventos_descricao
           FROM ((((((((public.folhas_pagamento fp
             JOIN public.funcionarios f ON ((f.id = fp.funcionario_id)))
             LEFT JOIN public.identidades_secretas i ON ((i.funcionario_id = f.id)))
             LEFT JOIN public.cargos c ON ((c.id = f.cargo_id)))
             LEFT JOIN public.departamentos d ON ((d.id = f.departamento_id)))
             LEFT JOIN active_team at ON (((at.funcionario_id = f.id) AND (at.rn = 1))))
             LEFT JOIN public.equipes e ON ((e.id = at.equipe_id)))
             LEFT JOIN public.bases b_1 ON ((b_1.id = e.base_principal_id)))
             LEFT JOIN event_totals et ON ((et.folha_pagamento_id = fp.id)))
        )
 SELECT folha_pagamento_id,
    funcionario_id,
    nome_completo,
    codinome,
    universo,
    exposicao_publica,
    cargo_id,
    cargo,
    departamento_id,
    departamento,
    equipe_id,
    equipe,
    papel_equipe,
    base_id,
    base,
    tipo_base,
    sigilo_base,
    ano,
    mes,
    competencia,
    data_pagamento,
    salario_bruto,
    total_descontos,
    salario_liquido,
    qtd_eventos,
    qtd_proventos,
    qtd_descontos,
    qtd_adicionais,
    qtd_tipos_evento,
    valor_proventos,
    valor_descontos_eventos,
    valor_adicionais,
    ((valor_adicionais - valor_descontos_eventos))::numeric(18,2) AS saldo_eventos,
    ((salario_liquido - salario_bruto))::numeric(18,2) AS saldo_liquido_vs_bruto,
    round((total_descontos / NULLIF(salario_bruto, (0)::numeric)), 4) AS pct_desconto,
    round((salario_liquido / NULLIF(salario_bruto, (0)::numeric)), 4) AS pct_liquido,
    round((valor_adicionais / NULLIF(salario_bruto, (0)::numeric)), 4) AS pct_adicionais_sobre_bruto,
    round((valor_descontos_eventos / NULLIF(salario_bruto, (0)::numeric)), 4) AS pct_eventos_desconto_sobre_bruto,
        CASE
            WHEN (salario_bruto < (12000)::numeric) THEN 'ATE_12K'::text
            WHEN (salario_bruto < (25000)::numeric) THEN '12K_25K'::text
            WHEN (salario_bruto < (40000)::numeric) THEN '25K_40K'::text
            WHEN (salario_bruto < (60000)::numeric) THEN '40K_60K'::text
            ELSE '60K_PLUS'::text
        END AS faixa_salario_bruto,
        CASE
            WHEN (salario_liquido < (10000)::numeric) THEN 'ATE_10K'::text
            WHEN (salario_liquido < (20000)::numeric) THEN '10K_20K'::text
            WHEN (salario_liquido < (35000)::numeric) THEN '20K_35K'::text
            WHEN (salario_liquido < (50000)::numeric) THEN '35K_50K'::text
            ELSE '50K_PLUS'::text
        END AS faixa_salario_liquido,
        CASE
            WHEN ((total_descontos / NULLIF(salario_bruto, (0)::numeric)) < 0.18) THEN 'ATE_18_PCT'::text
            WHEN ((total_descontos / NULLIF(salario_bruto, (0)::numeric)) < 0.22) THEN '18_22_PCT'::text
            WHEN ((total_descontos / NULLIF(salario_bruto, (0)::numeric)) < 0.26) THEN '22_26_PCT'::text
            ELSE '26_PCT_PLUS'::text
        END AS faixa_pct_desconto,
        CASE
            WHEN (valor_adicionais = (0)::numeric) THEN 'SEM_ADICIONAL'::text
            WHEN (valor_adicionais < (1000)::numeric) THEN 'ADICIONAL_BAIXO'::text
            WHEN (valor_adicionais < (5000)::numeric) THEN 'ADICIONAL_MEDIO'::text
            ELSE 'ADICIONAL_ALTO'::text
        END AS faixa_valor_adicionais,
        CASE
            WHEN ((cargo ~~* '%agente%'::text) OR (departamento ~~* '%seguran%'::text)) THEN 'SECURITY'::text
            WHEN ((cargo ~~* '%piloto%'::text) OR (cargo ~~* '%comandante%'::text) OR (departamento ~~* '%explora%'::text)) THEN 'OPERATIONS'::text
            WHEN ((cargo ~~* '%cientista%'::text) OR (cargo ~~* '%engenheiro%'::text) OR (departamento ~~* '%p&d%'::text) OR (departamento ~~* '%pesquisa%'::text)) THEN 'RND'::text
            WHEN ((cargo ~~* '%repórter%'::text) OR (cargo ~~* '%reporter%'::text) OR (departamento ~~* '%comunica%'::text) OR (departamento ~~* '%jornalis%'::text)) THEN 'MEDIA'::text
            WHEN ((cargo ~~* 'CEO%'::text) OR (cargo ~~* 'Diretor%'::text)) THEN 'EXEC'::text
            ELSE 'GENERAL'::text
        END AS payroll_profile,
        CASE
            WHEN ((qtd_adicionais > 0) AND (qtd_descontos > 0)) THEN 'MISTA'::text
            WHEN (qtd_adicionais > 0) THEN 'COM_ADICIONAL'::text
            WHEN (qtd_descontos > 0) THEN 'COM_DESCONTO'::text
            ELSE 'BASICA'::text
        END AS composicao_folha,
    eventos_descricao
   FROM base b;


ALTER VIEW public.vw_analytics_folha_pagamento OWNER TO praxis_demo_owner;

--
-- Name: vw_indicadores_incidentes; Type: VIEW; Schema: public; Owner: praxis_demo_owner
--

CREATE VIEW public.vw_indicadores_incidentes AS
 SELECT i.id AS incidente_id,
    m.titulo AS missao,
    i.descricao,
    i.local,
    i.severidade,
    i.danos_civis,
    COALESCE(sum(inden.valor), (0)::numeric) AS total_indenizacoes,
    COALESCE(sum(
        CASE
            WHEN inden.pago THEN inden.valor
            ELSE (0)::numeric
        END), (0)::numeric) AS total_pago,
    COALESCE(sum(
        CASE
            WHEN (NOT inden.pago) THEN inden.valor
            ELSE (0)::numeric
        END), (0)::numeric) AS total_pendente,
    i.ocorrido_em
   FROM ((public.incidentes i
     LEFT JOIN public.indenizacoes inden ON ((inden.incidente_id = i.id)))
     LEFT JOIN public.missoes m ON ((m.id = i.missao_id)))
  GROUP BY i.id, m.titulo, i.descricao, i.local, i.severidade, i.danos_civis, i.ocorrido_em;


ALTER VIEW public.vw_indicadores_incidentes OWNER TO praxis_demo_owner;

--
-- Name: VIEW vw_indicadores_incidentes; Type: COMMENT; Schema: public; Owner: praxis_demo_owner
--

COMMENT ON VIEW public.vw_indicadores_incidentes IS 'Resumo de incidentes com danos e indenizações.';


--
-- Name: vw_perfil_heroi; Type: VIEW; Schema: public; Owner: praxis_demo_owner
--

CREATE VIEW public.vw_perfil_heroi AS
 SELECT f.id AS funcionario_id,
    f.nome_completo,
    i.codinome,
    i.universo,
    i.exposicao_publica,
    c.nome AS cargo,
    d.nome AS departamento,
    r.score_publico,
    r.score_governamental,
    (((r.score_publico + r.score_governamental))::numeric / (2)::numeric) AS score_medio,
    COALESCE(string_agg(h.nome, ', '::text ORDER BY h.nome), '-'::text) AS habilidades,
    e.nome AS equipe_principal,
    b.nome AS base_principal,
    f.foto_perfil_url AS avatar_url
   FROM (((((((((public.funcionarios f
     LEFT JOIN public.cargos c ON ((c.id = f.cargo_id)))
     LEFT JOIN public.departamentos d ON ((d.id = f.departamento_id)))
     LEFT JOIN public.identidades_secretas i ON ((i.funcionario_id = f.id)))
     LEFT JOIN public.funcionario_habilidades fh ON ((fh.funcionario_id = f.id)))
     LEFT JOIN public.habilidades h ON ((h.id = fh.habilidade_id)))
     LEFT JOIN public.equipe_membros em ON ((em.funcionario_id = f.id)))
     LEFT JOIN public.equipes e ON ((e.id = em.equipe_id)))
     LEFT JOIN public.bases b ON ((e.base_principal_id = b.id)))
     LEFT JOIN public.reputacoes r ON ((r.funcionario_id = f.id)))
  GROUP BY f.id, f.foto_perfil_url, f.nome_completo, i.codinome, i.universo, i.exposicao_publica, c.nome, d.nome, r.score_publico, r.score_governamental, e.nome, b.nome;


ALTER VIEW public.vw_perfil_heroi OWNER TO praxis_demo_owner;

--
-- Name: VIEW vw_perfil_heroi; Type: COMMENT; Schema: public; Owner: praxis_demo_owner
--

COMMENT ON VIEW public.vw_perfil_heroi IS 'Perfil completo do heroi com foto, cargo, equipe, base e habilidades.';


--
-- Name: vw_ranking_reputacao; Type: VIEW; Schema: public; Owner: praxis_demo_owner
--

CREATE VIEW public.vw_ranking_reputacao AS
 SELECT f.id AS funcionario_id,
    f.nome_completo,
    i.codinome,
    e.nome AS equipe,
    COALESCE(r.score_publico, 0) AS score_publico,
    COALESCE(r.score_governamental, 0) AS score_governamental,
    (((COALESCE(r.score_publico, 0) + COALESCE(r.score_governamental, 0)))::numeric / (2)::numeric) AS media,
    rank() OVER (ORDER BY ((COALESCE(r.score_publico, 0) + COALESCE(r.score_governamental, 0)) / 2) DESC) AS posicao
   FROM ((((public.funcionarios f
     LEFT JOIN public.identidades_secretas i ON ((i.funcionario_id = f.id)))
     LEFT JOIN public.reputacoes r ON ((r.funcionario_id = f.id)))
     LEFT JOIN public.equipe_membros em ON ((em.funcionario_id = f.id)))
     LEFT JOIN public.equipes e ON ((e.id = em.equipe_id)));


ALTER VIEW public.vw_ranking_reputacao OWNER TO praxis_demo_owner;

--
-- Name: VIEW vw_ranking_reputacao; Type: COMMENT; Schema: public; Owner: praxis_demo_owner
--

COMMENT ON VIEW public.vw_ranking_reputacao IS 'Ranking de reputação pública e governamental dos heróis.';


--
-- Name: vw_resumo_missoes; Type: VIEW; Schema: public; Owner: praxis_demo_owner
--

CREATE VIEW public.vw_resumo_missoes AS
 SELECT m.id AS missao_id,
    m.titulo,
    m.status,
    m.prioridade,
    m.local,
    a.nome AS ameaca,
    count(DISTINCT mp.funcionario_id) AS qtd_herois,
    count(DISTINCT me.id) AS qtd_eventos,
    min(me.ocorrido_em) AS primeira_acao,
    max(me.ocorrido_em) AS ultima_acao
   FROM (((public.missoes m
     LEFT JOIN public.ameacas a ON ((a.id = m.ameaca_id)))
     LEFT JOIN public.missao_participantes mp ON ((mp.missao_id = m.id)))
     LEFT JOIN public.missao_eventos me ON ((me.missao_id = m.id)))
  GROUP BY m.id, m.titulo, m.status, m.prioridade, m.local, a.nome;


